class Solution:
  def isBridge(self, u: int, v: int, graph: List[List[int]], disc: List[int], low: List[int], visited: List[bool], time: int) -> bool:
    if disc[u] == -1:
disc[u] = time
    if disc[v] == -1:
disc[v] = time

    low[u] = min(low[u], disc[v] + 1)
    return disc[u] > disc[v]

  def findBridges(self, n: int, graph: List[List[int]]) -> List[bool]:
    disc = [-1] * n
    low = [n] * n
    visited = [False] * n
    time = 0

    for i in range(n):
      if disc[i] == -1:
        self.dfs(i, i, graph, disc, low, visited, time)

    return [disc[u] > disc[v] for u, v in enumerate(graph)]


  def dfs(self, u, p, graph, disc, low, visited, time):
    visited[u] = True
    low[u] = disc[u] = time
    time += 1
    for v in graph[u]:
      if disc[v] == -1:
        self.dfs(v, u, graph, disc, low, visited, time)
        low[u] = min(low[u], low[v])
        if low[v] > disc[u]:
          return True
      elif visited[v]:
        if disc[v] < disc[u]:
          return True
    return False

