class Solution {
public:
bool isBridge(int u, int v, vector<vector<int>>& graph, vector<int>& disc, vector<int>& low, vector<bool>& visited, int& time)
{
    if (disc[u] == -1)
disc[u] = time++;
    if (disc[v] == -1)
disc[v] = time++;
    low[u] = min(low[u], disc[v] + 1);
    return disc[u] > disc[v];
}

bool findBridges(int n, vector<vector<int>>& graph)
{
    disc = vector<int>(n, -1);
    low = vector<int>(n, n);
    visited = vector<bool>(n, false);
    time = 0;

    for (int i = 0; i < n; i++)
        if (disc[i] == -1)
            dfs(i, i, graph, disc, low, visited, time);

    vector<bool> bridges(n, false);
    for (int i = 0; i < n; i++)
        bridges[i] = isBridge(i, i, graph, disc, low, visited, time);

    return bridges;
}

void dfs(int u, int p, vector<vector<int>>& graph, vector<int>& disc, vector<int>& low, vector<bool>& visited, int& time)
{
    visited[u] = true;
    low[u] = disc[u] = time;
    time++;
    for (int v : graph[u])
    {
        if (disc[v] == -1)
        {
            dfs(v, u, graph, disc, low, visited, time);
            low[u] = min(low[u], low[v]);
            if (low[v] > disc[u])
                return;
        }
        else if (visited[v])
        {
            if (disc[v] < disc[u])
                return;
        }
    }
}
